export const checkId = 'cors';
export const name = 'CORS Configured';
export const appliesTo = ['deployable', 'server', 'framework'];

const CORS_PATTERNS = [
  /require\s*\(\s*['"][^'"]*cors['"]\s*\)/,
  /import\s+.*?['"][^'"]*cors['"]/,
  /from\s+['"][^'"]*cors['"]/,
  /access-control-allow-origin/i,
  /access-control-allow-methods/i,
  /access-control-allow-headers/i,
  /access-control-allow-credentials/i,
  /access-control-expose-headers/i,
  /access-control-max-age/i,
  /access-control-request/i,
  /cors\s*:\s*(true|\{)/i,
  /cors\s*\(/i,
  /enableCors/i,
  /allowedOrigins?/i,
  /allowOrigin/i,
  /corsOrigins?/i,
  /use\s*\(\s*cors/i,
  /register\s*\([^)]*cors/i,
  /corsHandler/i,
  /handleCors/i,
  /withCors/i,
  /setHeader\s*\(\s*['"]Access-Control/i,
  /headers\s*\(\s*\)\s*\{[^}]*access-control/i,
];

const EXCLUDED_PATH_RX = /(^|\/)(node_modules|\.git|\.next|out|dist|build|coverage|\.tmp|test|tests|__tests__|spec|example|examples|demo|demos|fixtures|fixture|mock|mocks|docs|playground|storybook|e2e|cypress|vitest|jest|benchmark|benchmarks|perf)\//i;

const BACKEND_DEPS = ['express', 'fastify', 'koa', 'hono', 'elysia', 'hapi', 'sails', 'meteor', 'feathers', 'restify', 'polka', 'micro', 'connect', 'restana', '0http'];
const FULLSTACK_DEPS = ['next', 'nuxt', 'remix', '@remix-run/react', 'sveltekit', '@sveltejs/kit', 'astro', 'gatsby', 'blitz', 'redwood', '@redwoodjs/core'];

const WELL_KNOWN_CLIENT_LIBS = /^(axios|node-fetch|undici|ky|got|superagent|request|isomorphic-unfetch|cross-fetch|lodash|underscore|ramda|moment|dayjs|date-fns|chalk|debug|colors|qs|uuid|bcrypt|semver|glob|minimist|yargs|inquirer|ora|ms|mime|fresh|bytes|vary|methods|parseurl|path-to-regexp|merge-descriptors|content-type|cookie|cookie-signature|encodeurl|escape-html|http-errors|ipaddr\.js|media-typer|on-finished|proxy-addr|range-parser|raw-body|safe-buffer|safer-buffer|setprototypeof|statuses|type-is|unpipe|wrappy|yallist|lru-cache|ini|dotenv|cross-spawn|execa|which)\b/i;

function isTutorial(packageJson) {
  if (!packageJson) return false;
  const text = [
    packageJson.name,
    packageJson.description,
    ...(packageJson.keywords || []),
  ].filter(Boolean).join(' ').toLowerCase();
  return /\b(learn|tutorial|course|workshop|playground|cheatsheet|starter\s*kit|boilerplate|template\s*repo|example\s*repo|sample|getting-started|how[- ]?to|guide|introduction|teach|training|walkthrough)\b/.test(text);
}

function isLibraryOrFramework(packageJson, tree) {
  if (!packageJson) return false;

  const scripts = packageJson.scripts || {};
  const hasServerScript = !!(scripts.start || scripts.serve || scripts['start:prod'] || scripts.preview || scripts.deploy);
  const hasMain = !!(packageJson.main || packageJson.module || packageJson.exports || packageJson.typings || packageJson.types);
  const hasBin = !!packageJson.bin;
  const keywords = (packageJson.keywords || []).map(k => k.toLowerCase());
  const hasPeerDeps = !!(packageJson.peerDependencies && Object.keys(packageJson.peerDependencies).length > 0);
  const isPrivate = packageJson.private === true;

  const hasPackages = tree.some(p => /^packages\/[^/]+\/package\.json$/.test(p));
  const hasApps = tree.some(p => /^(apps|services|clients|web|www|site|sites|server|api|studio|dashboard|admin|portal|frontend|backend|workers|edge-functions)\/[^/]+\/package\.json$/.test(p));
  const hasWorkspaces = !!(packageJson.workspaces);

  if ((hasWorkspaces || hasPackages) && !hasApps && !hasServerScript && isPrivate) {
    return true;
  }

  if (hasPeerDeps) return true;
  if (hasBin && !hasServerScript) return true;

  if (hasMain && !hasServerScript) {
    const libKeywords = new Set(['library', 'plugin', 'sdk', 'toolkit', 'middleware', 'framework', 'client', 'util', 'utils', 'helper', 'module', 'tool', 'cli', 'component', 'components']);
    if (keywords.some(k => libKeywords.has(k))) return true;

    const name = (packageJson.name || '').toLowerCase();
    if (WELL_KNOWN_CLIENT_LIBS.test(name)) return true;
  }

  return false;
}

function hasCorsDep(packageJson) {
  if (!packageJson) return false;
  const depSets = [packageJson.dependencies, packageJson.devDependencies, packageJson.peerDependencies];
  for (const set of depSets) {
    if (!set) continue;
    for (const k of Object.keys(set)) {
      const base = k.includes('/') ? k.split('/').pop() : k;
      if (/cors/i.test(base)) return true;
    }
  }
  return false;
}

function hasBackendFramework(packageJson) {
  if (!packageJson) return false;
  const deps = { ...(packageJson.dependencies || {}), ...(packageJson.devDependencies || {}) };
  return BACKEND_DEPS.some(d => deps[d]);
}

function hasFullstackFramework(packageJson) {
  if (!packageJson) return false;
  const deps = { ...(packageJson.dependencies || {}), ...(packageJson.devDependencies || {}) };
  return FULLSTACK_DEPS.some(d => deps[d]);
}

function isApiRouteFile(p) {
  if (!/\.(js|ts|jsx|tsx|mjs|cjs|mts|cts)$/.test(p)) return false;
  if (EXCLUDED_PATH_RX.test(p)) return false;
  if (/(^|\/)node_modules\//.test(p)) return false;
  return /(^|\/)api\//.test(p) ||
    /(^|\/)pages\/api\//.test(p) ||
    /(^|\/)app\/api\//.test(p) ||
    /(^|\/)src\/pages\/api\//.test(p) ||
    /(^|\/)src\/app\/api\//.test(p) ||
    /(^|\/)server\/api\//.test(p) ||
    /\+server\.(ts|js|mjs|cjs)$/.test(p);
}

function isServerEntryFile(p) {
  if (!/\.(js|ts|mjs|cjs|jsx|tsx|mts|cts)$/.test(p)) return false;
  if (EXCLUDED_PATH_RX.test(p)) return false;
  if (/(^|\/)node_modules\//.test(p)) return false;
  const b = p.slice(p.lastIndexOf('/') + 1);
  return /^(server|listen|worker|main)\.(js|ts|mjs|cjs|jsx|tsx|mts|cts)$/.test(b);
}

function isConfigFile(p) {
  return /\.config\.(js|ts|mjs|cjs|mts|cts)$/.test(p) ||
    /^(vercel\.json|netlify\.toml|_headers|wrangler\.toml|fly\.toml|render\.yaml|railway\.toml|app\.yaml|Procfile|Dockerfile)/.test(p.slice(p.lastIndexOf('/') + 1));
}

export async function check(context) {
  const { tree, files, packageJson } = context;

  try {
    if (!tree || tree.length === 0) {
      return { checkId, status: 'not-applicable', confidence: 'high', message: 'Empty repository', findings: [] };
    }

    if (hasCorsDep(packageJson)) {
      return { checkId, status: 'pass', confidence: 'high', message: 'CORS dependency found in package.json', findings: [] };
    }

    if (isTutorial(packageJson)) {
      return { checkId, status: 'not-applicable', confidence: 'high', message: 'Tutorial or example repository — CORS not applicable', findings: [] };
    }

    if (isLibraryOrFramework(packageJson, tree)) {
      return { checkId, status: 'not-applicable', confidence: 'high', message: 'Library or framework source — CORS not applicable', findings: [] };
    }

    const candidates = [];
    for (const p of tree) {
      if (/(^|\/)node_modules\//.test(p)) continue;
      if (EXCLUDED_PATH_RX.test(p)) continue;

      let score = 0;
      if (isConfigFile(p)) score += 100;
      if (isApiRouteFile(p)) score += 80;
      if (isServerEntryFile(p)) score += 70;
      if (/middleware\.(js|ts|mjs|cjs)$/.test(p.slice(p.lastIndexOf('/') + 1))) score += 60;
      if (/(^|\/)routes\//.test(p) && /\.(js|ts|mjs|cjs)$/.test(p)) score += 50;
      if (/\.(js|ts|mjs|cjs)$/.test(p)) score += 10;

      if (score > 0) candidates.push({ path: p, score });
    }

    candidates.sort((a, b) => b.score - a.score);

    for (const { path } of candidates.slice(0, 80)) {
      const content = await files.get(path);
      if (!content) continue;
      for (const pat of CORS_PATTERNS) {
        if (pat.test(content)) {
          return { checkId, status: 'pass', confidence: 'high', message: `CORS configuration found in ${path}`, findings: [{ file: path, issue: 'CORS detected' }] };
        }
      }
    }

    const subPkgs = tree.filter(p => /(^|\/)package\.json$/.test(p) && !/node_modules/.test(p));
    for (const pkgPath of subPkgs.slice(0, 50)) {
      if (pkgPath === 'package.json') continue;
      const content = await files.get(pkgPath);
      if (!content) continue;
      try {
        const subPkg = JSON.parse(content);
        if (hasCorsDep(subPkg)) {
          return { checkId, status: 'pass', confidence: 'high', message: `CORS dependency found in ${pkgPath}`, findings: [{ file: pkgPath, issue: 'cors dependency detected' }] };
        }
      } catch {
        // ignore invalid JSON
      }
    }

    const hasApi = tree.some(isApiRouteFile);
    const hasServer = tree.some(isServerEntryFile);
    const hasBackend = hasBackendFramework(packageJson);
    const hasFullstack = hasFullstackFramework(packageJson);

    if (!hasApi && !hasServer) {
      return { checkId, status: 'not-applicable', confidence: 'high', message: 'No API routes or server entry points detected — CORS not needed', findings: [] };
    }

    if (hasFullstack) {
      return { checkId, status: 'check-it', confidence: 'medium', message: 'Full-stack app with server-side code detected — verify CORS is configured if cross-origin requests are expected', findings: [{ file: 'unknown', issue: 'CORS configuration may be needed' }] };
    }

    if (hasBackend || hasServer || hasApi) {
      return { checkId, status: 'fail', confidence: 'medium', message: 'Server-side API detected but no CORS configuration found', findings: [{ file: 'unknown', issue: 'Missing CORS configuration' }] };
    }

    return { checkId, status: 'check-it', confidence: 'low', message: 'Ambiguous server-side code — verify if CORS is needed', findings: [{ file: 'unknown', issue: 'CORS configuration may be needed' }] };
  } catch (err) {
    console.error(`[${checkId}] Unexpected error:`, err);
    return { checkId, status: 'check-it', confidence: 'low', message: `Error during CORS check: ${err.message}`, findings: [{ file: 'unknown', issue: `Error: ${err.message}` }] };
  }
}
